const body = $json.body || $json;

function normalizeText(value) {
  return String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

const rawMessage = body.mensagem || body.message || body.text || body.mensagem_cliente || '';
const msg = normalizeText(rawMessage);

const origem = body.origem || body.canal || body.channel || 'nao_informado';
const nome = body.nome || body.name || '';
const telefone = body.telefone || body.phone || body.whatsapp || '';
const email = body.email || '';
const condominio = body.condominio || body.empresa || body.condominio_escola_empresa || '';
const bairro = body.bairro || '';

function hasAny(list) {
  return list.some(term => msg.includes(normalizeText(term)));
}

const termosProibidos = [
  'visita técnica',
  'visita tecnica',
  'marcar visita',
  'agendar visita',
  'canaleta plástica',
  'canaleta plastica',
  'garantia vitalícia',
  'garantia vitalicia'
];

const termosProibidosEncontrados = termosProibidos.filter(term => msg.includes(normalizeText(term)));

const escopoHidraulicoPuro = hasAny([
  'vazamento',
  'cano furado',
  'encanamento',
  'troca de cano',
  'troca de tubulacao hidraulica',
  'troca de tubulação hidráulica',
  'conserto hidraulico',
  'conserto hidráulico',
  'manutencao hidraulica pura',
  'manutenção hidráulica pura',
  'reparo hidraulico',
  'reparo hidráulico',
  'mangueira estourada'
]);

const demandas = {
  dl_acqua_commander: hasAny([
    'bomba', 'cisterna', 'caixa dagua', 'caixa d agua', 'caixa d’água', 'boia', 'boia eletrica', 'nivel', 'sensor de nivel', 'recalque', 'painel de bomba', 'bomba parada', 'falta dagua', 'falta d agua', 'transbordando', 'transbordamento'
  ]),
  fortress: hasAny([
    'portaria', 'portaria autonoma', 'controle de acesso', 'facial', 'biometria', 'qr code', 'condfy', 'morador', 'visitante', 'prestador', 'acesso de moradores', 'cadastro de moradores'
  ]),
  gatekeeper: hasAny([
    'portao', 'portão', 'bluetooth', 'wireless', 'mobgate', 'controle remoto', 'abertura de portao', 'porta de rolagem', 'acesso por aplicativo'
  ]),
  cftv: hasAny([
    'camera', 'câmera', 'cftv', 'dvr', 'nvr', 'sem imagem', 'imagem ruim', 'camera offline', 'poe', 'switch poe', 'gravacao', 'gravação', 'hd do dvr', 'hikvision', 'intelbras'
  ]),
  eletrica: hasAny([
    'eletrica', 'elétrica', 'curto', 'disjuntor', 'quadro', 'queda de energia', 'sem energia', 'dps', 'dr', 'aterramento', 'circuito', 'iluminacao', 'iluminação', 'cabo aquecendo'
  ]),
  comandos: hasAny([
    'comando eletrico', 'comando elétrico', 'painel de comando', 'contator', 'rele', 'relé', 'temporizador', 'chave contatora', 'inversor de frequencia', 'inversor de frequência', 'botoeira', 'sinaleiro'
  ]),
  redes: hasAny([
    'rede', 'internet', 'roteador', 'switch', 'vlan', 'cabeamento estruturado', 'fibra', 'rack', 'wifi', 'wi-fi', 'ip', 'ping', 'infraestrutura de rede'
  ]),
  solar: hasAny([
    'solar', 'fotovoltaico', 'inversor solar', 'placa solar', 'painel solar', 'string', 'microinversor', 'bateria', 'sistema hibrido', 'sistema híbrido', 'off grid', 'on grid', 'geracao baixa', 'geração baixa'
  ]),
  incendio: hasAny([
    'incendio', 'incêndio', 'alarme de incendio', 'central de incendio', 'detector de fumaca', 'detector de fumaça', 'sirene', 'acionador manual', 'iluminacao de emergencia', 'iluminação de emergência'
  ]),
  recorrencia: hasAny([
    'contrato', 'manutencao preventiva', 'manutenção preventiva', 'manutencao recorrente', 'manutenção recorrente', 'sla', 'partner', 'acompanhamento mensal', 'plano mensal'
  ])
};

let produto_indicado = 'nao_classificado';
let area_tecnica = 'nao_classificada';
let prioridade = normalizeText(body.prioridade || 'media');
let risco = 'risco_nao_identificado';
let dados = [];
let encaminhar_para = 'Humano';
let precisa_avaliacao_tecnica = true;
let escopo_invalido = false;
let observacoes = [];

if (escopoHidraulicoPuro && !demandas.dl_acqua_commander && !demandas.comandos && !demandas.eletrica) {
  escopo_invalido = true;
  produto_indicado = 'fora_do_escopo_principal_dl';
  area_tecnica = 'hidraulica_pura';
  prioridade = 'media';
  risco = 'demanda_hidraulica_pura_fora_do_escopo_dl';
  encaminhar_para = 'Humano';
  dados = ['descrição do problema', 'fotos ou vídeos', 'informar se existe bomba, painel, boia, comando ou automação envolvidos'];
  observacoes.push('Demanda parece hidráulica pura. DL não deve assumir execução hidráulica direta.');
} else if (demandas.dl_acqua_commander || demandas.comandos) {
  produto_indicado = 'DL Acqua / DL Commander';
  area_tecnica = 'bombas_cisternas_comandos_automacao';
  prioridade = 'alta';
  risco = 'risco_de_falta_dagua_transbordamento_falha_de_bomba_ou_falha_de_comando';
  encaminhar_para = 'Orcamento';
  dados = ['fotos do painel de comando', 'foto da bomba', 'foto da boia ou sensor', 'descrição da falha', 'nome do condomínio ou escola', 'bairro', 'urgência', 'se o sistema está parado ou intermitente'];
} else if (demandas.fortress) {
  produto_indicado = 'Fortress';
  area_tecnica = 'portaria_autonoma_controle_de_acesso';
  prioridade = 'media';
  risco = 'risco_de_acesso_desorganizado_sem_rastreabilidade';
  encaminhar_para = 'Orcamento';
  dados = ['quantidade de acessos', 'quantidade aproximada de unidades ou usuários', 'sistema atual', 'se já existe controle facial ou biometria', 'bairro', 'fotos da portaria e acessos'];
} else if (demandas.gatekeeper) {
  produto_indicado = 'Gatekeeper';
  area_tecnica = 'automacao_de_portoes_e_acessos';
  prioridade = 'media';
  risco = 'risco_de_acesso_sem_controle_ou_sem_rastreabilidade';
  encaminhar_para = 'Orcamento';
  dados = ['tipo de portão', 'quantidade de usuários', 'local de instalação', 'tipo de acionamento atual', 'fotos do motor/comando quando houver'];
} else if (demandas.cftv) {
  produto_indicado = 'DL Guardião';
  area_tecnica = 'cftv_seguranca_eletronica';
  prioridade = msg.includes('sem imagem') || msg.includes('offline') ? 'alta' : 'media';
  risco = 'risco_de_perda_de_imagens_gravacao_ou_monitoramento';
  encaminhar_para = 'Suporte';
  dados = ['marca/modelo do DVR/NVR', 'quantidade de câmeras', 'foto da tela com erro', 'se há acesso remoto', 'se o gravador está ligado', 'fotos do rack ou equipamento'];
} else if (demandas.eletrica) {
  produto_indicado = 'DL Volt';
  area_tecnica = 'eletrica_infraestrutura';
  prioridade = hasAny(['curto', 'sem energia', 'cabo aquecendo', 'cheiro de queimado']) ? 'critica' : 'alta';
  risco = 'risco_eletrico_operacional_ou_de_seguranca';
  encaminhar_para = 'Suporte';
  dados = ['foto do quadro', 'descrição da falha', 'o que desarma', 'quando ocorre', 'carga envolvida', 'bairro', 'urgência'];
} else if (demandas.redes) {
  produto_indicado = 'Infraestrutura de Redes';
  area_tecnica = 'redes_de_computadores';
  prioridade = 'media';
  risco = 'risco_de_indisponibilidade_de_comunicacao_cftv_automacao_ou_acesso';
  encaminhar_para = 'Suporte';
  dados = ['topologia atual se existir', 'equipamentos envolvidos', 'foto do rack', 'quantidade de pontos', 'se há CFTV/controle de acesso na rede'];
} else if (demandas.solar) {
  produto_indicado = 'DL EcoVolt';
  area_tecnica = 'energia_solar';
  prioridade = 'media';
  risco = 'risco_de_baixa_geracao_falha_de_inversor_ou_dimensionamento_inadequado';
  encaminhar_para = 'Orcamento';
  dados = ['conta de energia', 'tipo de sistema desejado', 'foto do local de instalação', 'se há inversor instalado', 'se deseja bateria ou sistema híbrido'];
} else if (demandas.incendio) {
  produto_indicado = 'DL Alerta';
  area_tecnica = 'sistema_de_incendio_prevencao';
  prioridade = 'alta';
  risco = 'risco_de_falha_em_sistema_de_alerta_ou_prevencao';
  encaminhar_para = 'Suporte';
  dados = ['foto da central', 'mensagem de falha', 'quantidade de detectores', 'se há sirene/acionadores', 'bairro', 'urgência'];
} else if (demandas.recorrencia) {
  produto_indicado = 'DL Partner';
  area_tecnica = 'contrato_recorrente';
  prioridade = 'media';
  risco = 'risco_de_manutencao_corretiva_sem_previsibilidade';
  encaminhar_para = 'Orcamento';
  dados = ['sistemas existentes', 'quantidade de equipamentos', 'histórico de falhas', 'bairro', 'prioridade de SLA desejada'];
}

if (['critica', 'crítica'].includes(prioridade)) {
  encaminhar_para = 'Humano';
}

let resposta_cliente = '';

if (escopo_invalido) {
  resposta_cliente = 'A DL Soluções atua na parte elétrica, comando, automação, proteção, monitoramento e inteligência preventiva dos sistemas. Para intervenção hidráulica pura, como vazamento em canos ou reparo direto de encanamento, o ideal é acionar um profissional hidráulico. Caso o problema envolva bomba, painel, boia, recalque, proteção elétrica ou automação, podemos realizar uma Avaliação Técnica da parte elétrica e de comando.';
} else if (produto_indicado === 'nao_classificado') {
  resposta_cliente = 'Recebemos a solicitação. Para direcionarmos corretamente, precisamos entender melhor qual sistema está envolvido: elétrica, CFTV, controle de acesso, portões, cisterna, caixa d’água, energia solar, incêndio, redes ou contrato recorrente. Com essas informações, conseguimos indicar a próxima etapa com segurança.';
  precisa_avaliacao_tecnica = false;
  encaminhar_para = 'Aninha';
} else {
  resposta_cliente = `Análise técnica preliminar: a demanda foi relacionada a ${produto_indicado}. Para definir o escopo correto, infraestrutura, riscos, responsabilidades, setup, mensalidade, SLA, equipamentos, peças e chamados avulsos, o próximo passo recomendado é uma Avaliação Técnica da DL Soluções. Essa etapa evita orçamento incorreto e permite indicar a solução adequada para o condomínio ou escola.`;
}

if (demandas.recorrencia && produto_indicado !== 'DL Partner') {
  observacoes.push('Existe oportunidade de recorrência DL Partner associada a esta demanda.');
}

const saidaString = normalizeText(JSON.stringify({ resposta_cliente, produto_indicado, area_tecnica, risco }));
const violacoesSaida = termosProibidos.filter(term => saidaString.includes(normalizeText(term)));

let killcritic_status = violacoesSaida.length > 0 ? 'BLOQUEADO' : 'APROVADO';

if (killcritic_status === 'BLOQUEADO') {
  resposta_cliente = 'Recebemos a solicitação. Para avançarmos corretamente, o próximo passo recomendado é uma Avaliação Técnica da DL Soluções, com análise do cenário, riscos, infraestrutura e melhor solução para o condomínio ou escola.';
}

return [{
  json: {
    agente: 'Diego',
    versao: 'v3_killcritic',
    canal_origem: origem,
    nome,
    telefone,
    email,
    condominio_escola_empresa: condominio,
    bairro,
    mensagem_original: rawMessage,
    area_tecnica,
    produto_indicado,
    prioridade,
    risco_tecnico: risco,
    escopo_invalido,
    precisa_avaliacao_tecnica,
    dados_necessarios: dados,
    resposta_cliente,
    encaminhar_para,
    oportunidade_dl_partner: demandas.recorrencia || ['DL Acqua / DL Commander', 'Fortress', 'Gatekeeper', 'DL Guardião', 'DL Volt'].includes(produto_indicado),
    killcritic_status,
    termos_proibidos_entrada: termosProibidosEncontrados,
    termos_proibidos_saida: violacoesSaida,
    observacoes,
    proxima_acao: escopo_invalido ? 'validar_se_existe_escopo_eletrico_comando_automacao' : 'coletar_dados_minimos_e_preparar_avaliacao_tecnica',
    timestamp: new Date().toISOString()
  }
}];
